import React, { Component } from 'react';

export default class App extends Component {

  state = {
      direction: '',
      points: [],
      started: false,
      moveID: null,
      createID: null,
      hit: null,
      score: 0,
      message: ''
  }

  loopPoints = () => {
      let directions = ['up', 'right', 'down', 'left']
      let _createID = setTimeout(() => {
          this._createPoint(directions[Math.floor(Math.random()*3)])
          this.loopPoints();
      }, Math.round(Math.random() * (3000 - 500)) + 500);
      this.setState({createID: _createID})
  }

  clearPoints() {
      clearInterval(this.state.createID)
      this.setState({points: []})
  }

  _handlePoints = (isSetPlay) => {
      if (!isSetPlay) {
          this._stopPoints()
      }
      else {
          this._startPoints()
      }
  }

  _createPoint = (arrow) => {
      this.setState(({points}) => {
          return {
              points: [...points, {pos: 0, arrow: arrow, status: 0}]
          }
      })
  }

  _movePoints = () => {
      this.setState(({points}) => {
          let _points = points.map(el => ({ ...el, pos: el.pos + 1 }))
          return {
              points: _points,
          }
      })
  }

  _startPoints = () => {
      this.loopPoints()
      this.setState({moveID: setInterval(this._movePoints, 100)})
  }

  _stopPoints = () => {
      this.clearPoints()
      this.clearScore()
      clearInterval(this.state.moveID)
  }

  handleKeydown() {
      document.addEventListener("keydown", (e) => {
          if (e.repeat) return
          this.setDirection(e.code)
      }, false);
      document.addEventListener("keyup",(e) => {
          this.setDirection()
      });
  }

  handleButton = () => {
      this.setState(({started}) => {
          return {
              started: !started
          }
      }, () => this._handlePoints(this.state.started))
  }

  setButtonText() {
      return this.state.started ? 'Stop' : 'Start'
  }

  setIndicator = () => {
      switch (this.state.hit) {
          case false:
              return 'bad'
          case true:
              return 'good'
          default:
              return null
      }
  }

  checkScore(pos) {
      if (pos === -1) return 0
      if (pos === 50) return 300
      if (pos < 49 || pos > 51) return 100
      else return 200
  }

  setScore(pos) {
     this.setState({score: this.state.score + this.checkScore(pos)})
  }

  clearScore() {
      this.setState({score: 0})
  }

  checkHit(dir) {
      if (!this.state.started) return
      const matchedPoint = this.state.points.find(el => (el.pos >= 47  && el.pos <= 53) &&
                                                         dir === el.arrow &&
                                                         el.status !== 1)
      let position = matchedPoint ? matchedPoint.pos : -1
      this.setState({hit: !!matchedPoint})
      this.setScore(position)
  }

  setDirection(code) {
      let arrows = [
          'ArrowUp',
          'ArrowRight',
          'ArrowDown',
          'ArrowLeft',
      ]
      if (arrows.includes(code)) {
          let direction = code.replace('Arrow', '').toLowerCase()
          this.setState({ direction }, () => {
              this.checkHit(direction)
          });
      }
      else if (code === undefined) {
          this.setState({
              direction: null,
              hit: null
          })
      }
  }

  componentDidMount() {
      this.handleKeydown()
  }

  render() {
      return (
        <div className="App">
          <button className="btn" onClick={this.handleButton}>{this.setButtonText()}</button>
          <div className="score">{this.state.score}</div>
            <div className="score">points</div>
          <div className={`car ${this.state.direction}`}/>
          <Points points={this.state.points} hitCheck={this.setIndicator}/>
        </div>
        )

  };
}

const Points = ({points, hitCheck}) => {
    const elements = points.map((el, index) => {
        return <Point key={`point-${index}`} point={el} />
    })

    return (
        <div className={`line ${hitCheck()}`}>
            {elements}
        </div>
    )
}

const Point = ({point}) => {
    return (
        <div className={`point point-${point.arrow}`} style={{left: `${point.pos}%`}}>{point.pos}</div>
    )
}
